mapper.select:
/* selectTransportRecordList */ SELECT TP.VHPLNKY , TP.WAREKEY , MW.WHNAMLC , TP.TPNSTAT , TP.DOCCATE , MD.DOCCTNM , MD.DOCTYNM , TP.DOCTYPE , MC.COMCDTX as TPNAMLC , CASE WHEN TPW.TOTALWEIG IS NULL OR TPW.TOTALWEIG = 0 THEN SUM(TI.SKUWEIG) / 1000 ELSE TPW.TOTALWEIG END as TOTALWEIG , TPW.RENAMLCS , TPW.REGIKEYS , TPW.CTREGIKY , TPW.MNRENAMLC , CONCAT( DATE_FORMAT(TP.VHPDATE, '%Y/%m/%d'), ' ', CASE WHEN TP.VHPTIME IS NULL OR TRIM(TP.VHPTIME) = '' THEN '' ELSE STR_TO_DATE(TP.VHPTIME, '%H%i%s') END ) as VHPDATE , CONCAT( DATE_FORMAT(TP.STPITDT, '%Y/%m/%d'), ' ', CASE WHEN TP.STPITTM IS NULL OR TRIM(TP.STPITTM) = '' THEN '' ELSE STR_TO_DATE(TP.STPITTM, '%H%i%s') END ) as STPITDT , CONCAT( DATE_FORMAT(TP.TRNINDT, '%Y/%m/%d'), ' ', CASE WHEN TP.TRNINTM IS NULL OR TRIM(TP.TRNINTM) = '' THEN '' ELSE STR_TO_DATE(TP.TRNINTM, '%H%i%s') END ) as TRNINDT , TP.TRNMEMO , TP.APROVYN , MCA.COMCDTX as APNAMLC , CONCAT ( DATE_FORMAT(TP.APROVDT, '%Y/%m/%d'), ' ', CASE WHEN TP.APROVTM IS NULL OR TRIM(TP.APROVTM) = '' THEN '' ELSE STR_TO_DATE(TP.APROVTM, '%H%i%s') END ) as APROVDT , TP.UPDTCHK , '${param.schema}' AS SCHEMA_NAME FROM ${param.schema}.TPLNHD TP INNER JOIN ${param.schema}.MWARMA MW ON MW.WAREKEY = TP.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${param.schema}.MCODEM MC ON MC.COMCDKY = 'TPNSTAT' AND MC.COMCDVL = TP.TPNSTAT AND MC.COUSEYN = 'Y' INNER JOIN ${param.schema}.MCODEM MCA ON MCA.COMCDKY = 'APROVYN' AND MCA.COMCDVL = TP.APROVYN AND MCA.COUSEYN = 'Y' INNER JOIN ${param.schema}.MDOCMA MD ON MD.DOCCATE = TP.DOCCATE AND MD.WAREKEY = TP.WAREKEY AND MD.DOCTYPE = TP.DOCTYPE AND MD.DOUSEYN = 'Y' LEFT JOIN ${param.schema}.TPLNIT TI ON TI.WAREKEY = TP.WAREKEY AND TI.VHPLNKY = TP.VHPLNKY LEFT JOIN ( SELECT TW.VHPLNKY, GROUP_CONCAT(DISTINCT TW.REGIKEY SEPARATOR ', ') AS REGIKEYS, GROUP_CONCAT(DISTINCT MR.RENAMLC ORDER BY MR.RENAMLC ASC SEPARATOR ', ') AS RENAMLCS, COUNT(TW.REGIKEY) AS CTREGIKY, MIN(MR.RENAMLC) AS MNRENAMLC, SUM(TW.ALCWEIG) AS TOTALWEIG FROM ${param.schema}.TPWPWG TW INNER JOIN ${param.schema}.MREGMA MR ON MR.REGIKEY = TW.REGIKEY AND MR.REUSEYN = 'Y' GROUP BY TW.VHPLNKY ) TPW ON TPW.VHPLNKY = TP.VHPLNKY WHERE TP.VEHICKY = #{param.vehicky}
AND TP.VHPDATE BETWEEN #{param.vhpdateFrom} AND #{param.vhpdateTo}
AND TP.TPNSTAT = #{param.tpnstat}
AND TP.TPNSTAT != 'CANCEL'
AND TP.APROVYN = #{param.aprovyn}
GROUP BY TP.VHPLNKY, TP.WAREKEY, MW.WHNAMLC, TP.TPNSTAT , TP.TRNMEMO, TP.APROVYN, MCA.COMCDTX, MC.COMCDTX
HAVING FIND_IN_SET(#{param.regikey}, TPW.REGIKEYS) > 0
ORDER BY TP.VHPLNKY DESC
LIMIT #{param.limit}

/* selectMcodemList */
SELECT COMCDVL as COMBOVL
	 , COMCDTX as COMBONM
  FROM ${param.schema}.MCODEM
 WHERE COUSEYN = 'Y'

   AND COMCDKY = #{param.comcdky}


   AND COMCDVL = #{param.comcdvl}

 GROUP BY COMCDVL, COMCDTX
 ORDER BY COMCDOR ASC

/* selectTransportDetailHistoryItem */ SELECT TI.CUSTCOD , CASE WHEN TI.CUSTCOD IS NULL OR TRIM(TI.CUSTCOD) = '' THEN TI.CUSTNAM WHEN MCU.CUNAMLC IS NULL OR TRIM(MCU.CUNAMLC) = '' THEN TI.CUSTNAM ELSE MCU.CUNAMLC END AS CUSTNAM , TI.CUSTNAM , MCU.CUSTELN , TI.TPISTAT , MCO.COMCDTX AS TINAMLC
, TI.REGIMOD
, CASE WHEN TW.REGIKEY IS NULL OR TRIM(TW.REGIKEY) = '' THEN TI.REGIMOD ELSE TW.REGIKEY END AS REGIKEY
, MR.RENAMLC , TI.DESTORG , CASE WHEN TI.DESTORG IS NULL OR TRIM(TI.DESTORG) = '' THEN TI.DEORGNM WHEN MDO.DENAMLC IS NULL OR TRIM(MDO.DENAMLC) = '' THEN TI.DEORGNM ELSE MDO.DENAMLC END AS DEORGNM , TI.DESTMOD , CASE WHEN TI.DESTMOD IS NULL OR TRIM(TI.DESTMOD) = '' THEN TI.DEMODNM WHEN MDM.DENAMLC IS NULL OR TRIM(MDM.DENAMLC) = '' THEN TI.DEMODNM ELSE MDM.DENAMLC END AS DEMODNM , MDM.DESMEMO , TI.DEMDMAN , TI.DEMPOCD , TI.DEMDADR , TI.DEMDTLN , TI.SKUMKEY , TI.SKUWIDT , TI.SKULENG , TI.SKUTHIC , TI.SKUWEIG , TI.GROSSWD , TI.GROSSLN , TI.GROSSTH , TI.GROSSWG , TI.STKMEMO , TI.SHPPLKY , TI.SHPPLIT , TI.UPDTCHK , TI.VHPLNKY , TI.VHPLNIT , TI.WAREKEY , CONCAT( DATE_FORMAT(TI.TRNCPDT, '%Y.%m.%d'), ' ', CASE WHEN TI.TRNCPTM IS NULL OR TRIM(TI.TRNCPTM) = '' THEN '' ELSE STR_TO_DATE(TI.TRNCPTM, '%H%i%s') END ) as TRNCPDT FROM ${param.schema}.TPLNIT TI LEFT JOIN ${param.schema}.MCUSMA MCU ON MCU.CUSTKEY = TI.CUSTCOD AND MCU.CUDELYN = 'Y' INNER JOIN ${param.schema}.MCODEM MCO ON MCO.COMCDKY = 'TPISTAT' AND MCO.COMCDVL = TI.TPISTAT AND MCO.COUSEYN = 'Y' INNER JOIN ${param.schema}.TPLNHD TP ON TP.VHPLNKY = TI.VHPLNKY AND TP.WAREKEY = TI.WAREKEY
INNER JOIN ${param.schema}.MREGMA MR ON MR.REGIKEY = TI.REGIMOD AND MR.REUSEYN = 'Y'
INNER JOIN ${param.schema}.TPWPWG TW ON TW.VHPLNKY = TI.VHPLNKY AND (CASE WHEN TI.SHPPLKY IS NOT NULL THEN TW.SHPPLKY ELSE TI.SHPPLKY END) = TW.SHPPLKY INNER JOIN ${param.schema}.MREGMA MR ON MR.REGIKEY = CASE WHEN TW.REGIKEY IS NULL OR TRIM(TW.REGIKEY) = '' THEN TI.REGIMOD ELSE TW.REGIKEY END AND MR.REUSEYN = 'Y'
LEFT JOIN ${param.schema}.MDESMA MDO ON MDO.REGIKEY = TI.REGIORG AND MDO.CUSTKEY = TI.CUSTCOD AND MDO.DESTKEY = TI.DESTORG AND MDO.DEUSEYN = 'Y' LEFT JOIN ${param.schema}.MDESMA MDM ON MDM.REGIKEY = TI.REGIMOD AND MDM.CUSTKEY = TI.CUSTCOD AND MDM.DESTKEY = TI.DESTMOD AND MDM.DEUSEYN = 'Y' WHERE TI.VHPLNKY = #{param.vhplnky} AND TI.WAREKEY = #{param.warekey}
AND TI.CUSTCOD = #{param.custcod}
AND TI.CUSTNAM = #{param.custnam}
AND TI.DEMODNM = #{param.demodnm}
ORDER BY TI.VHPLNIT ASC

