/* userFcmTokenUpdate */
UPDATE ${param.commonSchema}.SUSRMA
   SET FCMTOKN = #{param.fcmtokn}
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{param.useract}
     , UPDTCHK = UPDTCHK + 1
WHERE USERACT = #{param.useract}
  AND USERKEY = #{param.userkey}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${param.commonSchema}.SUSRMA WHERE USERACT = #{param.useract})

