/* selectUserFcmToken */
SELECT SU.USERACT
     , SU.FCMTOKN
FROM PH_COMMON.SUSRMA SU
WHERE SU.USERACT = #{param.useract}

/* selectAlarmControlParameterName */
SELECT ML.LOCAKEY
	 , ML.LOCANAM
FROM ${param.schema}.MLOCMA ML
INNER JOIN ${param.schema}.MWARMA MW
	ON MW.WAREKEY = ML.WAREKEY
   AND MW.WHUSEYN = 'Y'
WHERE ML.WAREKEY = #{param.warekey}
  AND ML.LOCAKEY = #{param.destination}
  AND ML.AREAKEY = #{param.areakey}

