/* updateAppAprovyn */
UPDATE ${param.schema}.TPLNHD
   SET APROVYN = #{param.aprovyn}

	     , TPNSTAT = #{param.tpnstat}
	     , TRCNLDT = DATE_FORMAT(NOW(), '%Y%m%d')
	     , TRCNLTM = DATE_FORMAT(NOW(), '%H%i%s')

     , APROVDT = DATE_FORMAT(NOW(), '%Y%m%d')
     , APROVTM = DATE_FORMAT(NOW(), '%H%i%s')
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{param.useract}
     , UPDTCHK = UPDTCHK + 1
WHERE VHPLNKY = #{param.vhplnky}
  AND WAREKEY = #{param.warekey}
  AND VEHICKY = #{param.vehicky}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${param.schema}.TPLNHD WHERE VHPLNKY = #{param.vhplnky})

/* updateAppVehicleStatusHead */
UPDATE ${param.schema}.TPLNHD
   SET TPNSTAT = #{param.tpnstat}

     , STPITDT = DATE_FORMAT(NOW(), '%Y%m%d')
     , STPITTM = DATE_FORMAT(NOW(), '%H%i%s')


     , TRNINDT = DATE_FORMAT(NOW(), '%Y%m%d')
     , TRNINTM = DATE_FORMAT(NOW(), '%H%i%s')

     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{param.useract}
     , UPDTCHK = UPDTCHK + 1
WHERE VHPLNKY = #{param.vhplnky}
  AND WAREKEY = #{param.warekey}
  AND VEHICKY = #{param.vehicky}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${param.schema}.TPLNHD WHERE VHPLNKY = #{param.vhplnky})

/* updateAppVehicleStatusItem */
UPDATE ${param.schema}.TPLNIT
   SET TPISTAT = #{param.tpistat}

   	 , TRNCPDT = DATE_FORMAT(NOW(), '%Y%m%d')
	 , TRNCPTM = DATE_FORMAT(NOW(), '%H%i%s')
	 , BILDATE = DATE_FORMAT(NOW(), '%Y%m%d')

     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{param.useract}
     , UPDTCHK = UPDTCHK + 1
WHERE VHPLNKY = #{param.vhplnky}
  AND WAREKEY = #{param.warekey}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${param.schema}.TPLNIT WHERE VHPLNKY = #{param.vhplnky} AND VHPLNIT = #{param.vhplnit})
  AND VHPLNIT = #{param.vhplnit}

	AND CUSTCOD = #{param.custcod}


	AND CUSTNAM = #{param.custnam}


	AND DEMODNM = #{param.demodnm}

/* updateTpwpwgArrivyn */
UPDATE ${param.schema}.TPWPWG
   SET ARRIVYN = 'Y'
     , UPDTCHK = #{param.updtchk} + 1
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{param.lmouser}
WHERE VHPLNKY = #{param.vhplnky}
  AND SHPPLKY = #{param.shpplky}
  AND PLNSIZE = #{param.plnsize}
  AND UPDTCHK = #{param.updtchk}

mapper.select:
/* selectAppComeinVehicleList */
SELECT WH.EOASNKY, WH.UPDTCHK, WH.WAREKEY, '${param.schema}' AS SCHEMA_NAME
FROM ${param.schema}.WASNHD WH
WHERE WH.VOWNKEY = #{param.vownkey}
   AND WH.VEHICKY = #{param.vehicky}
   AND (WH.ENTDATE IS NULL OR WH.ENTDATE = '')
   AND (WH.ENTTIME IS NULL OR WH.ENTTIME = '')
   AND ( WH.ASNSTAT = 'ACONF' OR ( WH.ASNSTAT = 'PCONF' AND NOT EXISTS
	   (SELECT WI.EOASNKY, WI.EOASNIT FROM ${param.schema}.WASNIT WI WHERE WI.EOASNKY = WH.EOASNKY AND WI.ASNITST = 'NEW')));

mapper.update:
/* updateAppComeinVehicle */
UPDATE ${param.schema}.WASNHD WAS
INNER JOIN ${param.schema}.MWARMA MWA
	ON MWA.WAREKEY = WAS.WAREKEY
   SET WAS.ENTDOYN = IF(MWA.CNTRLYN = 'Y', 'N', 'Y')
   	 , WAS.ENTDATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , WAS.ENTTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , WAS.ASNITYN = 'Y'
     , WAS.LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , WAS.LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , WAS.LMOUSER = #{param.useract}
     , WAS.UPDTCHK = #{param.updtchk} + 1
WHERE WAS.EOASNKY = #{param.eoasnky}
  AND WAS.WAREKEY = #{param.warekey}
  AND WAS.UPDTCHK = #{param.updtchk}

/* updateAppComeinVehicle */
UPDATE ${param.schema}.OOUBHD OOU
INNER JOIN ${param.schema}.MWARMA MWA
	ON MWA.WAREKEY = OOU.WAREKEY
   SET OOU.ENTDOYN = IF(MWA.CNTRLYN = 'Y', 'N', 'Y')
     , OOU.ENTDATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , OOU.ENTTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , OOU.LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , OOU.LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , OOU.LMOUSER = #{param.useract}
     , OOU.UPDTCHK = #{param.updtchk} + 1
WHERE OOU.OUTBOKY = #{param.outboky}
  AND OOU.WAREKEY = #{param.warekey}
  AND OOU.UPDTCHK = #{param.updtchk}

