/* deleteAlarm */
DELETE FROM ${param.schema}.ALRMHI
WHERE ALARMKY = #{param.alarmky}
  AND WAREKEY = #{param.warekey}
  AND VOWNKEY = #{param.vownkey}
  AND VEHICKY = #{param.vehicky}
  AND USERACT = #{param.useract}
  AND ALRMCOD = #{param.alrmcod}

mapper.update:
/* updateCarryCheck */
UPDATE ${param.schema}.WASNIT
   SET STLAYER = (SELECT COUNT(1) FROM ${param.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky})
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{param.useract}
     , UPDTCHK = UPDTCHK + 1
WHERE EOASNKY = #{param.eoasnky}
  AND WAREKEY = #{param.warekey}
  AND STLAYER = #{param.stlayer}
  AND EOASNIT = #{param.eoasnit}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${param.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey} AND EOASNIT = #{param.eoasnit})

/* updateCarryHeadStatus */
UPDATE ${param.schema}.WASNHD
   SET ASNPIYN = #{param.asnpiyn}
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{param.useract}
     , UPDTCHK = UPDTCHK + 1
WHERE EOASNKY = #{param.eoasnky}
  AND WAREKEY = #{param.warekey}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${param.schema}.WASNHD WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey})

	/* changeStlayer */
	UPDATE ${param.schema}.WASNIT
	   SET STLAYER = #{param.stlayer}
	     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
	     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
	     , LMOUSER = #{param.useract}
	     , UPDTCHK = UPDTCHK + 1
	WHERE EOASNKY = #{param.eoasnky}
	  AND WAREKEY = #{param.warekey}
      AND UPDTCHK = (SELECT UPDTCHK FROM ${param.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey} AND STLAYER = (
      	SELECT COUNT(1) FROM ${param.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey}
      ))
      AND STLAYER = (SELECT COUNT(1) FROM ${param.schema}.WASNIT WHERE EOASNKY = #{param.eoasnky} AND WAREKEY = #{param.warekey})

mapper.select:
/* selectAppReleaseHeadList */ SELECT WH.SHPDCKY , WH.WAREKEY , MW.WHNAMLC , WH.DOCCATE , WH.DOCTYPE , MD.DOCCTNM , MD.DOCTYNM , WH.SHPDCST , MC.COMCDTX , WH.SHPWEIG , WH.REGIKEY , MR.RENAMLC , CONCAT ( DATE_FORMAT(WH.WPLNDAT, '%Y/%m/%d'), ' ', CASE WHEN WH.WPLNTIM IS NULL OR TRIM(WH.WPLNTIM) = '' THEN '' ELSE STR_TO_DATE(WH.WPLNTIM, '%H%i%s') END) as WPLNDAT , CONCAT ( DATE_FORMAT(WH.OBODATE, '%Y/%m/%d'), ' ', CASE WHEN WH.OBOTIME IS NULL OR TRIM(WH.OBOTIME) = '' THEN '' ELSE STR_TO_DATE(WH.OBOTIME, '%H%i%s') END) as OBODATE , CONCAT ( DATE_FORMAT(WH.SHPSDAY, '%Y/%m/%d'), ' ', CASE WHEN WH.SHPSTIM IS NULL OR TRIM(WH.SHPSTIM) = '' THEN '' ELSE STR_TO_DATE(WH.SHPSTIM, '%H%i%s') END) as SHPSDAY , CONCAT ( DATE_FORMAT(WH.SPEHDAT, '%Y/%m/%d'), ' ', CASE WHEN WH.SPEHTIM IS NULL OR TRIM(WH.SPEHTIM) = '' THEN '' ELSE STR_TO_DATE(WH.SPEHTIM, '%H%i%s') END) as SPEHDAT , '${param.schema}' AS SCHEMA_NAME FROM ${param.schema}.WSHPHD WH INNER JOIN ${param.schema}.MWARMA MW ON MW.WAREKEY = WH.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${param.schema}.MDOCMA MD ON MD.WAREKEY = WH.WAREKEY AND MD.DOCCATE = WH.DOCCATE AND MD.DOCTYPE = WH.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${param.schema}.MREGMA MR ON MR.REGIKEY = WH.REGIKEY AND MR.REUSEYN = 'Y' INNER JOIN ${param.schema}.MCODEM MC ON MC.COMCDKY = 'SHPDCST' AND MC.COMCDVL = WH.SHPDCST AND MC.COUSEYN = 'Y' WHERE WH.VOWNKEY = #{param.vownkey} AND WH.VEHICKY = #{param.vehicky}
AND WH.SHPSDAY BETWEEN #{param.shpsdayFrom} AND #{param.shpsdayTo}
AND WH.REGIKEY = #{param.regikey}

